-- 20260312093000_naesin_review_logs_and_analysis_v1.sql -- Naesin Reading Review Logs + Analysis Snapshots v1 begin; create extension if not exists pgcrypto; create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end; $$; create table if not exists public.naesin_reading_review_evidence_logs ( id uuid primary key default gen_random_uuid(), session_id uuid not null references public.naesin_reading_sessions(id) on delete cascade, question_id uuid not null references public.naesin_reading_questions(id) on delete cascade, passage_id uuid not null references public.naesin_reading_passages(id) on delete cascade, selected_evidence text[] not null default '{}'::text[], matched boolean not null default false, note text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(session_id, question_id) ); create table if not exists public.naesin_reading_review_unknown_word_logs ( id uuid primary key default gen_random_uuid(), session_id uuid not null references public.naesin_reading_sessions(id) on delete cascade, passage_id uuid not null references public.naesin_reading_passages(id) on delete cascade, words text[] not null default '{}'::text[], created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(session_id, passage_id) ); create table if not exists public.naesin_reading_review_sentence_analysis_logs ( id uuid primary key default gen_random_uuid(), session_id uuid not null references public.naesin_reading_sessions(id) on delete cascade, question_id uuid not null references public.naesin_reading_questions(id) on delete cascade, passage_id uuid not null references public.naesin_reading_passages(id) on delete cascade, target_sentence text not null, translation_ko text, subject_text text, verb_text text, object_text text, complement_text text, modifier_text text, note text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(session_id, question_id) ); create table if not exists public.naesin_reading_review_vocab_logs ( id uuid primary key default gen_random_uuid(), session_id uuid not null references public.naesin_reading_sessions(id) on delete cascade, passage_id uuid not null references public.naesin_reading_passages(id) on delete cascade, word text not null, prompt_sentence text, cloze_text text, user_answer text, is_correct boolean not null default false, attempt_no integer not null default 1, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(session_id, passage_id, word, attempt_no) ); create table if not exists public.naesin_reading_session_analysis_snapshots ( session_id uuid primary key references public.naesin_reading_sessions(id) on delete cascade, student_id uuid not null references auth.users(id) on delete cascade, set_id uuid not null references public.naesin_reading_sets(id) on delete cascade, accuracy_overall numeric(5,2), score_percent numeric(5,2), by_question_type jsonb not null default '{}'::jsonb, by_passage jsonb not null default '{}'::jsonb, evidence_metrics jsonb not null default '{}'::jsonb, vocab_metrics jsonb not null default '{}'::jsonb, sentence_metrics jsonb not null default '{}'::jsonb, behavior_metrics jsonb not null default '{}'::jsonb, weak_tags text[] not null default '{}'::text[], prescriptions text[] not null default '{}'::text[], created_at timestamptz not null default now(), updated_at timestamptz not null default now() ); create table if not exists public.naesin_reading_student_tendency_snapshots ( id uuid primary key default gen_random_uuid(), student_id uuid not null references auth.users(id) on delete cascade, window_size integer not null check (window_size > 0), basis_session_ids uuid[] not null default '{}'::uuid[], weak_tags text[] not null default '{}'::text[], top_patterns jsonb not null default '{}'::jsonb, prescription_tags text[] not null default '{}'::text[], created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(student_id, window_size) ); create index if not exists idx_naesin_review_evidence_logs_session_id on public.naesin_reading_review_evidence_logs(session_id); create index if not exists idx_naesin_review_evidence_logs_question_id on public.naesin_reading_review_evidence_logs(question_id); create index if not exists idx_naesin_review_evidence_logs_passage_id on public.naesin_reading_review_evidence_logs(passage_id); create index if not exists idx_naesin_review_unknown_word_logs_session_id on public.naesin_reading_review_unknown_word_logs(session_id); create index if not exists idx_naesin_review_unknown_word_logs_passage_id on public.naesin_reading_review_unknown_word_logs(passage_id); create index if not exists idx_naesin_review_sentence_analysis_logs_session_id on public.naesin_reading_review_sentence_analysis_logs(session_id); create index if not exists idx_naesin_review_sentence_analysis_logs_question_id on public.naesin_reading_review_sentence_analysis_logs(question_id); create index if not exists idx_naesin_review_sentence_analysis_logs_passage_id on public.naesin_reading_review_sentence_analysis_logs(passage_id); create index if not exists idx_naesin_review_vocab_logs_session_id on public.naesin_reading_review_vocab_logs(session_id); create index if not exists idx_naesin_review_vocab_logs_passage_id on public.naesin_reading_review_vocab_logs(passage_id); create index if not exists idx_naesin_review_vocab_logs_word on public.naesin_reading_review_vocab_logs(word); create index if not exists idx_naesin_session_analysis_snapshots_student_id on public.naesin_reading_session_analysis_snapshots(student_id); create index if not exists idx_naesin_session_analysis_snapshots_set_id on public.naesin_reading_session_analysis_snapshots(set_id); create index if not exists idx_naesin_student_tendency_snapshots_student_id on public.naesin_reading_student_tendency_snapshots(student_id); drop trigger if exists trg_naesin_review_evidence_logs_updated_at on public.naesin_reading_review_evidence_logs; create trigger trg_naesin_review_evidence_logs_updated_at before update on public.naesin_reading_review_evidence_logs for each row execute function public.set_updated_at(); drop trigger if exists trg_naesin_review_unknown_word_logs_updated_at on public.naesin_reading_review_unknown_word_logs; create trigger trg_naesin_review_unknown_word_logs_updated_at before update on public.naesin_reading_review_unknown_word_logs for each row execute function public.set_updated_at(); drop trigger if exists trg_naesin_review_sentence_analysis_logs_updated_at on public.naesin_reading_review_sentence_analysis_logs; create trigger trg_naesin_review_sentence_analysis_logs_updated_at before update on public.naesin_reading_review_sentence_analysis_logs for each row execute function public.set_updated_at(); drop trigger if exists trg_naesin_review_vocab_logs_updated_at on public.naesin_reading_review_vocab_logs; create trigger trg_naesin_review_vocab_logs_updated_at before update on public.naesin_reading_review_vocab_logs for each row execute function public.set_updated_at(); drop trigger if exists trg_naesin_session_analysis_snapshots_updated_at on public.naesin_reading_session_analysis_snapshots; create trigger trg_naesin_session_analysis_snapshots_updated_at before update on public.naesin_reading_session_analysis_snapshots for each row execute function public.set_updated_at(); drop trigger if exists trg_naesin_student_tendency_snapshots_updated_at on public.naesin_reading_student_tendency_snapshots; create trigger trg_naesin_student_tendency_snapshots_updated_at before update on public.naesin_reading_student_tendency_snapshots for each row execute function public.set_updated_at(); alter table public.naesin_reading_review_evidence_logs enable row level security; alter table public.naesin_reading_review_unknown_word_logs enable row level security; alter table public.naesin_reading_review_sentence_analysis_logs enable row level security; alter table public.naesin_reading_review_vocab_logs enable row level security; alter table public.naesin_reading_session_analysis_snapshots enable row level security; alter table public.naesin_reading_student_tendency_snapshots enable row level security; drop policy if exists "naesin_review_evidence_logs_select_own" on public.naesin_reading_review_evidence_logs; create policy "naesin_review_evidence_logs_select_own" on public.naesin_reading_review_evidence_logs for select using ( exists ( select 1 from public.naesin_reading_sessions s where s.id = session_id and s.student_id = auth.uid() ) ); drop policy if exists "naesin_review_evidence_logs_insert_own" on public.naesin_reading_review_evidence_logs; create policy "naesin_review_evidence_logs_insert_own" on public.naesin_reading_review_evidence_logs for insert with check ( exists ( select 1 from public.naesin_reading_sessions s where s.id = session_id and s.student_id = auth.uid() ) ); drop policy if exists "naesin_review_evidence_logs_update_own" on public.naesin_reading_review_evidence_logs; create policy "naesin_review_evidence_logs_update_own" on public.naesin_reading_review_evidence_logs for update using ( exists ( select 1 from public.naesin_reading_sessions s where s.id = session_id and s.student_id = auth.uid() ) ) with check ( exists ( select 1 from public.naesin_reading_sessions s where s.id = session_id and s.student_id = auth.uid() ) ); drop policy if exists "naesin_review_unknown_word_logs_select_own" on public.naesin_reading_review_unknown_word_logs; create policy "naesin_review_unknown_word_logs_select_own" on public.naesin_reading_review_unknown_word_logs for select using ( exists ( select 1 from public.naesin_reading_sessions s where s.id = session_id and s.student_id = auth.uid() ) ); drop policy if exists "naesin_review_unknown_word_logs_insert_own" on public.naesin_reading_review_unknown_word_